# solution.py
# FoodChain System
# This system connects customers, restaurants, and delivery personnel for efficient food delivery and management.

class FoodChain:
    def __init__(self):
        self.customers = {}
        self.restaurants = {}
        self.delivery_personnel = {}
        self.orders = {}

    def add_customer(self, customer_id, customer_info):
        self.customers[customer_id] = customer_info

    def add_restaurant(self, restaurant_id, restaurant_info):
        self.restaurants[restaurant_id] = restaurant_info

    def add_delivery_personnel(self, personnel_id, personnel_info):
        self.delivery_personnel[personnel_id] = personnel_info

    def place_order(self, order_id, customer_id, restaurant_id, items):
        if customer_id in self.customers and restaurant_id in self.restaurants:
            self.orders[order_id] = {
                'customer_id': customer_id,
                'restaurant_id': restaurant_id,
                'items': items,
                'status': 'placed'
            }
            return True
        return False

    def update_order_status(self, order_id, new_status):
        if order_id in self.orders:
            self.orders[order_id]['status'] = new_status
            return True
        return False

    def assign_delivery(self, order_id, personnel_id):
        if order_id in self.orders and personnel_id in self.delivery_personnel:
            self.orders[order_id]['delivery_personnel_id'] = personnel_id
            self.update_order_status(order_id, 'assigned')
            return True
        return False

    def get_order_status(self, order_id):
        if order_id in self.orders:
            return self.orders[order_id]['status']
        return None

# Example usage
