    food_chain = FoodChain()
    food_chain.add_customer('C001', {'name': 'John Doe', 'address': '123 Elm St'})
    food_chain.add_restaurant('R001', {'name': 'Pizza Place', 'menu': ['Pizza', 'Pasta']})
    food_chain.add_delivery_personnel('D001', {'name': 'Jane Smith', 'vehicle': 'Bike'})

    food_chain.place_order('O001', 'C001', 'R001', ['Pizza'])
    food_chain.assign_delivery('O001', 'D001')
    print(food_chain.get_order_status('O001'))  # Output: assigned
```

